    }
    _mobileTelemetry.track(
      eventName: MobileEventNames.routeLeave,
      category: 'join',
      addBreadcrumb: true,
      attributes: <String, Object?>{
        'result': leavePlan.telemetryResult,
        'routeId': routeId,
      },
    );
    _mobileTelemetry.trackPerf(
      eventName: MobileEventNames.leaveRouteCallableLatency,
      durationMs: stopwatch.elapsedMilliseconds,
      attributes: <String, Object?>{
        'result': leavePlan.telemetryResult,
