    }
  } on FirebaseFunctionsException catch (_) {
    if (!context.mounted) {
      return;
    }
    final leavePlan = _planPassengerRouteLeaveOutcomeHandlingUseCase.execute(
      const PlanPassengerRouteLeaveOutcomeHandlingCommand.failure(),
    );
    _mobileTelemetry.track(
      eventName: MobileEventNames.routeLeave,
      category: 'join',
      addBreadcrumb: true,
      attributes: <String, Object?>{
        'result': leavePlan.telemetryResult,
      },
    );
    _mobileTelemetry.trackPerf(
      eventName: MobileEventNames.leaveRouteCallableLatency,
      durationMs: stopwatch.elapsedMilliseconds,
      attributes: <String, Object?>{
        'result': leavePlan.telemetryResult,
      },
    );
    _showInfo(
      context,
      _resolvePassengerActionFailureFeedbackMessageUseCase.execute(
        PassengerActionFailureFeedbackKind.leaveRouteFailed,
      ),
    );
  }
